// // This module compares two 8-bit numbers and outputs 0 if they are equal.
module comparator (
    input [7:0] a,
    input [7:0] b,
    output reg eq
);

    always @(*) begin
        if (a == b) begin
            eq = 1;
        end else begin
            eq = 0;
        end
    end

endmodule
